def gen(rng, size):
    n = max(1, min(size, 60000))
    arr = [rng.randint(1, 9)]
    for _ in range(n - 1):
        arr.append(rng.randint(1, 9) if rng.random() < 0.8 else None)
    while arr and arr[-1] is None:
        arr.pop()
    return [arr]

