class Solution:
    def pseudoPalindromicPaths(self, root):
        from collections import Counter
        self.count = 0
        def dfs(node, path):
            if not node:
                return
            path.append(node.val)
            if not node.left and not node.right:
                c = Counter(path)
                odd = sum(1 for v in c.values() if v % 2 == 1)
                if odd <= 1:
                    self.count += 1
            else:
                dfs(node.left, path)
                dfs(node.right, path)
            path.pop()
        dfs(root, [])
        return self.count

