class Solution:
    def pseudoPalindromicPaths(self, root):
        self.count = 0
        def dfs(node, mask):
            if not node:
                return
            mask ^= (1 << node.val)
            if not node.left and not node.right:
                if mask & (mask - 1) == 0:
                    self.count += 1
            else:
                dfs(node.left, mask)
                dfs(node.right, mask)
        dfs(root, 0)
        return self.count

